import Link from '@/component/link'
import cn from 'clsx'
import React, { useMemo } from 'react'
import classes from '../style/index.module.styl'

export interface PostListPaginationProps {
  /**
   * Current page number.
   */
  current: number
  /**
   * Count of total pages.
   */
  totalPage: number
  /**
   * Pagination url prefix.
   */
  resolveUrl(pageNo: number): string | null
}

export function PostListPagination(
  props: PostListPaginationProps,
): React.ReactElement {
  const { current, totalPage, resolveUrl } = props
  const pagination = useMemo<React.ReactElement>(() => {
    const firstPageUrl: string = resolveUrl(1)!
    const prevPageUrl: string | null = resolveUrl(current - 1)
    const nextPageUrl: string | null = resolveUrl(current + 1)
    const lastPageUrl: string = resolveUrl(totalPage)!

    const minimumPageNo = Math.max(1, current - 3)
    const maximumPageNo = Math.min(totalPage, current + 3)
    const paginationBtns: React.ReactNode[] = []
    for (let i = minimumPageNo; i <= maximumPageNo; ++i) {
      paginationBtns.push(
        <li
          key={i}
          className={cn(classes.paginationItem, {
            [classes.paginationItemActive]: i === current,
          })}
        >
          <Link url={resolveUrl(i)!}>{i}</Link>
        </li>,
      )
    }

    return (
      <ul className={classes.pagination}>
        {prevPageUrl != null && (
          <li key="prev" className={classes.paginationItem}>
            <Link key="first-page" url={firstPageUrl}>
              «
            </Link>
            <Link key="prev-page" url={prevPageUrl}>
              Prev
            </Link>
            &nbsp;&nbsp;
          </li>
        )}
        {paginationBtns}
        {nextPageUrl != null && (
          <li key="next" className={classes.paginationItem}>
            &nbsp;&nbsp;
            <Link key="first-page" url={nextPageUrl}>
              Next
            </Link>
            <Link key="last-page" url={lastPageUrl}>
              »
            </Link>
          </li>
        )}
      </ul>
    )
  }, [current, totalPage, resolveUrl])
  return pagination
}

export default PostListPagination
